// LoadEvent loads the rsInfo's Event into the .R struct
func (os RSInfoSlice) LoadEvent(ctx context.Context, exec bob.Executor, mods ...bob.Mod[*dialect.SelectQuery]) error {
	if len(os) == 0 {
		return nil
	}

	events, err := os.Event(mods...).All(ctx, exec)
	if err != nil {
		return err
	}

	for _, o := range os {
		if o == nil {
			continue
		}

		o.R.Event = nil
		o.R.Loaded.Event = true
	}
	// O(N+M) stitch via a map keyed by the join column (key -> []parent; was O(N*M)).
	rsInfoByKey := make(map[int32][]*RSInfo, len(os))
	for _, o := range os {
		if o == nil {
			continue
		}

		rsInfoByKey[o.EventID] = append(rsInfoByKey[o.EventID], o)
	}

	for _, rel := range events {

		owners, ok := rsInfoByKey[rel.ID]
		if !ok {
			continue
		}

		for _, o := range owners {

			// to-one: keep only the first matching child (matches the previous break)
			if o.R.Event != nil {
				continue
			}

			rel.R.RSInfos = append(rel.R.RSInfos, o)

			o.R.Event = rel

		}
	}

	return nil
}

